// Built-in default callouts per map -- one anchor point (radar-normalized 0..1,
// top-left origin) at the centre of each named area. These drive nearest-anchor
// (Voronoi) classification so every position resolves to a call-out out of the box.
// Users can clone a map's defaults into their own named set and rename / move /
// redraw them (see lib/maps/zones.ts).
//
// Generated by the default-callouts workflow (author + critic pass). Coordinates are
// a best-effort starting point -- refine them in the zone editor.

export interface Callout {
  name: string;
  x: number; // 0 = left edge, 1 = right edge of the radar
  y: number; // 0 = top edge, 1 = bottom edge of the radar
  site: "A" | "B" | "Mid" | "other";
}

